```ts
const lastEntry = entityHistory[entityHistory.length - 1];
const filtered = entityHistory.filter(ent => ent.lu < purgeBeforePythonTime);
if (filtered.length === 0) {
  filtered.push(lastEntry);
}
filtered[0].lu = purgeBeforePythonTime;
