I don't know what other datastructures could show up either, but I don't think it'll hurt to check. I like opening it up, but what about checking if it is iterable and not hashable, like:

```py
def _is_non_hashable_iterable(value: Any) -> bool:
    return isinstance(value, Iterable) and not isinstance(value, Hashable)

def _recursive_iterable_to_tuple(itr: Iterable[Any]) -> Any:
    return tuple(
        _recursive_iterable_to_tuple(i) if _is_non_hashable_iterable(i) else i
        for i in itr
    )

def mapping_to_attrdict_hashable(d: Mapping[TKey, TValue]) -> AttributeDict[TKey, TValue]:
    """
    This method converts a ``Mapping`` to an ``AttributeDict`` while converting any
    un-hashable ``Iterable`` dict values to hashable ``tuple`` types.
    """

    ret = dict()
    for k, v in d.items():
        if isinstance(v, Mapping):
            ret[k] = mapping_to_attrdict_hashable(v)
        elif _is_non_hashable_iterable(v):
            ret[k] = _recursive_iterable_to_tuple(v)
        else:
            ret[k] = v
    return AttributeDict(ret)
```

